using System; using UnityEngine; using UnityEngine.UI; namespace DungeonSlash { public sealed class ResultView : MonoBehaviour { [SerializeField] private GameObject panel; [SerializeField] private Text title; [SerializeField] private Text details; [SerializeField] private Button restart; public void Configure(GameObject newPanel, Text newTitle, Text newDetails, Button newRestart) { panel = newPanel; title = newTitle; details = newDetails; restart = newRestart; } public void Show(string heading, string body, Action restartAction) { panel.SetActive(true); title.text = heading; details.text = body; restart.onClick.RemoveAllListeners(); restart.onClick.AddListener(() => restartAction()); } public void Hide() => panel.SetActive(false); } }
